___CSS_LOADER_EXPORT___.push([module.id, `.theme-classic-dark{--f-bg:#111827;--f-bg-card:#1f2937;--f-bg-input:#374151;--f-bg-hover:#4b5563;--f-text:#e5e7eb;--f-text-secondary:#9ca3af;--f-text-muted:#6b7280;--f-border:#374151;--f-border-hover:#4b5563;--f-accent:#60a5fa;--f-accent-bg:#2563eb;--f-accent-bg-hover:#3b82f6;--f-accent-dim:#1e3a5f;--f-author:#4ade80;--f-danger:#f87171;--f-danger-bg:#7f1d1d}.theme-classic-dark .forum-window{box-shadow:inset 0 1px 0 rgba(255,255,255,0.04)}.theme-cyberpunk{--f-bg:#0a0a1a;--f-bg-card:#12122e;--f-bg-input:#1a1a42;--f-bg-hover:#252560;--f-text:#d0d0ff;--f-text-secondary:#8888cc;--f-text-muted:#555588;--f-border:#2a2a5e;--f-border-hover:#3a3a7e;--f-accent:#00ffff;--f-accent-bg:#0099bb;--f-accent-bg-hover:#00bbdd;--f-accent-dim:#003344;--f-author:#ff00ff;--f-danger:#ff3366;--f-danger-bg:#4d0022}.theme-cyberpunk .forum-window{text-shadow:0 0 10px rgba(0,255,255,0.06)}.theme-vaporwave{--f-bg:#1a0a2e;--f-bg-card:#2d1b4e;--f-bg-input:#3d2d6e;--f-bg-hover:#4d3d8e;--f-text:#f0e0ff;--f-text-secondary:#c8a0e0;--f-text-muted:#8866aa;--f-border:#4d3d7e;--f-border-hover:#5d4d9e;--f-accent:#ff71ce;--f-accent-bg:#b967ff;--f-accent-bg-hover:#cc77ff;--f-accent-dim:#4a1942;--f-author:#01cdfe;--f-danger:#ff6b6b;--f-danger-bg:#4a1919}.theme-vaporwave .forum-window{background:linear-gradient(180deg,rgba(255,113,206,0.05) 0%,transparent 25%,rgba(185,103,255,0.03) 50%,transparent 75%,rgba(255,113,206,0.04) 100%)}.theme-terminal{--f-bg:#0a0a0a;--f-bg-card:#141414;--f-bg-input:#1e1e1e;--f-bg-hover:#282828;--f-text:#33ff33;--f-text-secondary:#22cc22;--f-text-muted:#117711;--f-border:#224422;--f-border-hover:#336633;--f-accent:#33ff33;--f-accent-bg:#22aa22;--f-accent-bg-hover:#33cc33;--f-accent-dim:#113311;--f-author:#88ff88;--f-danger:#ff4444;--f-danger-bg:#330000}.theme-terminal .forum-window{background-image:repeating-linear-gradient(0deg,transparent,transparent 2px,rgba(51,255,51,0.015) 2px,rgba(51,255,51,0.015) 4px)}.theme-terminal .fa-solid,.theme-terminal .fa-robot{color:var(--f-accent)}.theme-light{--f-bg:#f3f4f6;--f-bg-card:#ffffff;--f-bg-input:#e5e7eb;--f-bg-hover:#d1d5db;--f-text:#111827;--f-text-secondary:#4b5563;--f-text-muted:#9ca3af;--f-border:#d1d5db;--f-border-hover:#9ca3af;--f-accent:#2563eb;--f-accent-bg:#2563eb;--f-accent-bg-hover:#1d4ed8;--f-accent-dim:#dbeafe;--f-author:#059669;--f-danger:#dc2626;--f-danger-bg:#fee2e2}.theme-light .forum-window{box-shadow:inset 0 1px 0 rgba(255,255,255,0.8)}.theme-dark-gold{--f-bg:#0d0d0d;--f-bg-card:#171714;--f-bg-input:#252520;--f-bg-hover:#33332c;--f-text:#e8dcc8;--f-text-secondary:#a09078;--f-text-muted:#6b5e4e;--f-border:#3a3020;--f-border-hover:#5a4a30;--f-accent:#c9a84c;--f-accent-bg:#b08d38;--f-accent-bg-hover:#c9a84c;--f-accent-dim:#2a2410;--f-author:#d4a574;--f-danger:#b54a3a;--f-danger-bg:#3d1a14}.theme-dark-gold .forum-window{box-shadow:inset 0 1px 0 rgba(201,168,76,0.08),inset 0 -1px 0 rgba(0,0,0,0.4)}.theme-dark-gold .fa-solid,.theme-dark-gold .fa-robot{color:var(--f-accent);text-shadow:0 0 6px rgba(201,168,76,0.25)}.theme-parchment{--f-bg:#ddd5c5;--f-bg-card:#d0c8b8;--f-bg-input:#c8c0b0;--f-bg-hover:#c0b8a8;--f-text:#362618;--f-text-secondary:#5c4a32;--f-text-muted:#887a64;--f-border:#c0b8a0;--f-border-hover:#b4ac90;--f-accent:#7a5a10;--f-accent-bg:#7a5a10;--f-accent-bg-hover:#8f6e18;--f-accent-dim:#e8e0d0;--f-author:#4a6830;--f-danger:#9c3a2a;--f-danger-bg:#ead8d0}.theme-parchment .forum-window{background-image:url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.85' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)' opacity='0.04'/%3E%3C/svg%3E"),radial-gradient(ellipse at center,transparent 50%,rgba(54,38,24,0.04) 100%)}.forum-window{width:100%;height:100%}
`, "",{"version":3,"sources":["webpack://./src/Zsd网游论坛/App.vue"],"names":[],"mappings":"AAuiBA,oBACE,cAAe,CACf,mBAAoB,CACpB,oBAAqB,CACrB,oBAAqB,CACrB,gBAAiB,CACjB,0BAA2B,CAC3B,sBAAuB,CACvB,kBAAmB,CACnB,wBAAyB,CACzB,kBAAmB,CACnB,qBAAsB,CACtB,2BAA4B,CAC5B,sBAAuB,CACvB,kBAAmB,CACnB,kBAAmB,CACnB,qBACF,CACA,kCACE,+CACF,CACA,iBACE,cAAe,CACf,mBAAoB,CACpB,oBAAqB,CACrB,oBAAqB,CACrB,gBAAiB,CACjB,0BAA2B,CAC3B,sBAAuB,CACvB,kBAAmB,CACnB,wBAAyB,CACzB,kBAAmB,CACnB,qBAAsB,CACtB,2BAA4B,CAC5B,sBAAuB,CACvB,kBAAmB,CACnB,kBAAmB,CACnB,qBACF,CACA,+BACE,yCACF,CACA,iBACE,cAAe,CACf,mBAAoB,CACpB,oBAAqB,CACrB,oBAAqB,CACrB,gBAAiB,CACjB,0BAA2B,CAC3B,sBAAuB,CACvB,kBAAmB,CACnB,wBAAyB,CACzB,kBAAmB,CACnB,qBAAsB,CACtB,2BAA4B,CAC5B,sBAAuB,CACvB,kBAAmB,CACnB,kBAAmB,CACnB,qBACF,CACA,+BACE,mJAQF,CACA,gBACE,cAAe,CACf,mBAAoB,CACpB,oBAAqB,CACrB,oBAAqB,CACrB,gBAAiB,CACjB,0BAA2B,CAC3B,sBAAuB,CACvB,kBAAmB,CACnB,wBAAyB,CACzB,kBAAmB,CACnB,qBAAsB,CACtB,2BAA4B,CAC5B,sBAAuB,CACvB,kBAAmB,CACnB,kBAAmB,CACnB,qBACF,CACA,8BACE,gIAOF,CACA,oDAEE,qBACF,CACA,aACE,cAAe,CACf,mBAAoB,CACpB,oBAAqB,CACrB,oBAAqB,CACrB,gBAAiB,CACjB,0BAA2B,CAC3B,sBAAuB,CACvB,kBAAmB,CACnB,wBAAyB,CACzB,kBAAmB,CACnB,qBAAsB,CACtB,2BAA4B,CAC5B,sBAAuB,CACvB,kBAAmB,CACnB,kBAAmB,CACnB,qBACF,CACA,2BACE,8CACF,CACA,iBACE,cAAe,CACf,mBAAoB,CACpB,oBAAqB,CACrB,oBAAqB,CACrB,gBAAiB,CACjB,0BAA2B,CAC3B,sBAAuB,CACvB,kBAAmB,CACnB,wBAAyB,CACzB,kBAAmB,CACnB,qBAAsB,CACtB,2BAA4B,CAC5B,sBAAuB,CACvB,kBAAmB,CACnB,kBAAmB,CACnB,qBACF,CACA,+BACE,6EAGF,CACA,sDAEE,qBAAsB,CACtB,yCACF,CACA,iBACE,cAAe,CACf,mBAAoB,CACpB,oBAAqB,CACrB,oBAAqB,CACrB,gBAAiB,CACjB,0BAA2B,CAC3B,sBAAuB,CACvB,kBAAmB,CACnB,wBAAyB,CACzB,kBAAmB,CACnB,qBAAsB,CACtB,2BAA4B,CAC5B,sBAAuB,CACvB,kBAAmB,CACnB,kBAAmB,CACnB,qBACF,CACA,+BACE,uZAGF,CACA,cACE,UAAW,CACX,WACF","sourcesContent":["<template>\n  <div\n    class=\"forum-window relative flex flex-col text-[var(--f-text)] h-full overflow-hidden\"\n    :class=\"`theme-${settingsStore.settings.Ztheme}`\"\n    :style=\"{ backgroundColor: 'var(--f-bg)', color: 'var(--f-text)', ...customThemeVars }\"\n  >\n    <!-- 自定义背景层 -->\n    <div\n      v-if=\"settingsStore.settings.ZbgImage\"\n      class=\"absolute inset-0 bg-cover bg-center bg-no-repeat pointer-events-none z-0\"\n      :style=\"bgImageStyle\"\n    />\n    <!-- 毛玻璃层（独立，不受 opacity 影响） -->\n    <div\n      v-if=\"settingsStore.settings.ZbgImage && settingsStore.settings.ZbgBlur > 0\"\n      class=\"absolute inset-0 pointer-events-none z-[1]\"\n      :style=\"bgBlurStyle\"\n    />\n    <!-- 颜色遮罩层（负责半透明暗化） -->\n    <div\n      v-if=\"settingsStore.settings.ZbgImage\"\n      class=\"absolute inset-0 pointer-events-none z-[1]\"\n      :style=\"bgOverlayStyle\"\n    />\n    <!-- 内容层 -->\n    <div class=\"relative z-[2] flex flex-col h-full\">\n    <!-- 全局生成中提示 -->\n    <div\n      v-if=\"forumStore.isGenerating\"\n      class=\"shrink-0 flex items-center justify-between gap-1.5 py-1 px-2 text-[10px] font-medium\"\n      :style=\"{ backgroundColor: 'var(--f-accent-bg)', color: '#fff' }\"\n    >\n      <div class=\"flex items-center gap-1.5\">\n        <i class=\"fa-solid fa-spinner fa-spin\"></i>\n        <span>AI 正在生成内容，请稍候…</span>\n        <span v-if=\"forumStore.generationElapsed > 0\" class=\"opacity-80\">({{ forumStore.generationElapsed }}s)</span>\n      </div>\n      <button\n        class=\"px-1.5 py-0.5 rounded text-[10px] font-bold hover:opacity-80 transition-opacity\"\n        :style=\"{ backgroundColor: 'var(--f-danger)', color: '#fff' }\"\n        @click=\"forumStore.abortGeneration()\"\n      >\n        <i class=\"fa-solid fa-stop\"></i> 终止\n      </button>\n    </div>\n    <ForumTabs\n      :active-section=\"forumStore.activeSection\"\n      @switch=\"forumStore.switchSection($event)\"\n      @toggle-settings=\"showSettings = !showSettings\"\n      @refresh=\"handleRefresh\"\n      @close=\"requestClose\"\n    />\n\n    <!-- 论坛板块 -->\n    <PostList\n      v-if=\"currentSectionType === 'forum' && !forumStore.selectedPostId && !forumStore.showEditor && !showSettings\"\n      :posts=\"forumStore.currentPosts\"\n      @select=\"forumStore.selectPost($event)\"\n      @delete=\"forumStore.deletePost($event)\"\n    />\n    <PostDetail\n      v-else-if=\"currentSectionType === 'forum' && forumStore.selectedPostId && !forumStore.showEditor && !showSettings\"\n      :post=\"forumStore.selectedPost\"\n      :generating=\"forumStore.isGenerating\"\n      @back=\"forumStore.goBack()\"\n      @generate-comments=\"handleGenerateComments\"\n      @add-comment=\"forumStore.openCommentEditor()\"\n      @delete=\"handleDeletePost\"\n    />\n\n    <!-- 赛事板块 -->\n    <div v-if=\"currentSectionType === 'tournament' && !forumStore.selectedPostId && !forumStore.showEditor && !showSettings\" class=\"flex-1 overflow-y-auto p-2 space-y-2\">\n      <div v-if=\"forumStore.currentPosts.length === 0\" class=\"text-center text-[var(--f-text-muted)] text-xs py-8\">\n        <span class=\"font-bold\">暂无比赛记录，点击下方按钮生成</span>\n      </div>\n      <TournamentCard\n        v-for=\"post in forumStore.currentPosts\"\n        :key=\"post.id\"\n        :post=\"post\"\n        @click=\"forumStore.selectPost(post.id)\"\n        @delete=\"forumStore.deletePost($event)\"\n      />\n    </div>\n    <TournamentDetail\n      v-else-if=\"currentSectionType === 'tournament' && forumStore.selectedPostId && !forumStore.showEditor && !showSettings\"\n      :post=\"forumStore.selectedPost\"\n      :generating=\"forumStore.isGenerating\"\n      @back=\"forumStore.goBack()\"\n      @generate-comments=\"handleGenerateComments\"\n      @add-comment=\"forumStore.openCommentEditor()\"\n      @delete=\"handleDeletePost\"\n    />\n\n    <!-- 报纸板块 -->\n    <div v-if=\"currentSectionType === 'newspaper' && !forumStore.selectedPostId && !forumStore.showEditor && !showSettings\" class=\"flex-1 overflow-y-auto p-2 space-y-2\">\n      <div v-if=\"forumStore.currentPosts.length === 0\" class=\"text-center text-[var(--f-text-muted)] text-xs py-8\">\n        <span class=\"font-bold\">暂无报纸，点击下方按钮生成</span>\n      </div>\n      <NewspaperCard\n        v-for=\"post in forumStore.currentPosts\"\n        :key=\"post.id\"\n        :post=\"post\"\n        @click=\"forumStore.selectPost(post.id)\"\n        @delete=\"forumStore.deletePost($event)\"\n      />\n    </div>\n    <NewspaperDetail\n      v-else-if=\"currentSectionType === 'newspaper' && forumStore.selectedPostId && !forumStore.showEditor && !showSettings\"\n      :post=\"forumStore.selectedPost\"\n      :generating=\"forumStore.isGenerating\"\n      @back=\"forumStore.goBack()\"\n      @generate-comments=\"handleGenerateComments\"\n      @add-comment=\"forumStore.openCommentEditor()\"\n      @delete=\"handleDeletePost\"\n    />\n\n    <PostEditor\n      v-if=\"forumStore.showEditor && !showSettings\"\n      :mode=\"forumStore.editorMode\"\n      :section=\"forumStore.activeSection\"\n      :post-id=\"forumStore.selectedPostId ?? undefined\"\n      @cancel=\"forumStore.closeEditor()\"\n      @submit-post=\"handleSubmitPost\"\n      @submit-comment=\"handleSubmitComment\"\n    />\n\n    <!-- 底部操作栏 -->\n    <div v-if=\"!forumStore.selectedPostId && !forumStore.showEditor && !showSettings\" class=\"p-2 flex gap-1\" :style=\"{ borderTop: '1px solid var(--f-border)' }\">\n      <button\n        class=\"flex-1 text-[11px] text-white py-1.5 rounded disabled:opacity-50 transition-colors\"\n        :class=\"forumStore.isGenerating ? 'bg-[var(--f-bg-input)] cursor-wait' : 'bg-[var(--f-accent-bg)] hover:bg-[var(--f-accent-bg-hover)]'\"\n        :disabled=\"forumStore.isGenerating\"\n        @click=\"openGenDialog()\"\n      >\n        <i :class=\"forumStore.isGenerating ? 'fa-solid fa-spinner fa-spin' : 'fa-solid fa-robot'\"></i>\n        {{ forumStore.isGenerating ? '生成中...' : genButtonText }}\n      </button>\n      <button\n        class=\"text-[11px] px-3 py-1.5 rounded bg-[var(--f-bg-input)] hover:bg-[var(--f-bg-hover)] text-[var(--f-text)]\"\n        :disabled=\"forumStore.isGenerating\"\n        @click=\"forumStore.openPostEditor()\"\n      >\n        <i class=\"fa-solid fa-pen\"></i> {{ postButtonText }}\n      </button>\n    </div>\n\n    <!-- 生成对话框 -->\n    <div v-if=\"forumStore.showGenDialog && !showSettings\" class=\"absolute inset-0 z-20 flex flex-col p-3\" :style=\"{ backgroundColor: 'var(--f-bg)' }\">\n      <div class=\"flex items-center justify-between mb-3\">\n        <span class=\"text-sm font-bold text-[var(--f-text)]\">\n          <i class=\"fa-solid fa-robot text-[var(--f-accent)]\"></i> {{ forumStore.showGenLog ? '生成日志' : genDialogTitle }}\n        </span>\n        <div class=\"flex items-center gap-2\">\n          <button\n            v-if=\"!forumStore.showGenLog\"\n            class=\"text-[10px] px-1.5 py-0.5 rounded border text-[var(--f-text-secondary)] hover:text-[var(--f-text)] hover:border-[var(--f-text)] transition-colors\"\n            :style=\"{ borderColor: 'var(--f-border)' }\"\n            @click=\"forumStore.openGenLog()\"\n          >\n            <i class=\"fa-solid fa-clipboard-list\"></i> 日志\n          </button>\n          <button\n            v-else\n            class=\"text-[10px] px-1.5 py-0.5 rounded border text-[var(--f-text-secondary)] hover:text-[var(--f-text)] hover:border-[var(--f-text)] transition-colors\"\n            :style=\"{ borderColor: 'var(--f-border)' }\"\n            @click=\"forumStore.closeGenLog()\"\n          >\n            <i class=\"fa-solid fa-arrow-left\"></i> 返回\n          </button>\n          <button class=\"text-[var(--f-text-secondary)] hover:text-[var(--f-text)]\" @click=\"forumStore.closeGenDialog(); forumStore.closeGenLog()\">\n            <i class=\"fa-solid fa-xmark\"></i>\n          </button>\n        </div>\n      </div>\n\n      <!-- 生成设置 -->\n      <template v-if=\"!forumStore.showGenLog\">\n        <div class=\"space-y-3 flex-1 overflow-y-auto\">\n          <div>\n            <label class=\"text-[11px] text-[var(--f-text-secondary)] block mb-1\">生成模式</label>\n            <div class=\"flex gap-2 text-[11px]\">\n              <label class=\"flex items-center gap-1 cursor-pointer\">\n                <input v-model=\"genMode\" type=\"radio\" value=\"single\" class=\"accent-[var(--f-accent)]\">\n                <span>仅当前板块</span>\n              </label>\n              <label class=\"flex items-center gap-1 cursor-pointer\">\n                <input v-model=\"genMode\" type=\"radio\" value=\"merged\" class=\"accent-[var(--f-accent)]\">\n                <span>合并生成</span>\n              </label>\n              <label class=\"flex items-center gap-1 cursor-pointer\">\n                <input v-model=\"genMode\" type=\"radio\" value=\"sequential\" class=\"accent-[var(--f-accent)]\">\n                <span>独立生成</span>\n              </label>\n            </div>\n            <p v-if=\"genMode === 'merged' && settingsStore.settings.Zsections.length > 3\" class=\"text-[10px] text-[var(--f-danger)] mt-1\">\n              <i class=\"fa-solid fa-triangle-exclamation\"></i> 板块超过3个时，合并生成可能不可靠，建议使用独立生成\n            </p>\n          </div>\n          <div v-if=\"genMode !== 'single'\">\n            <label class=\"text-[11px] text-[var(--f-text-secondary)] block mb-1\">选择板块</label>\n            <div class=\"flex flex-wrap gap-2 text-[11px]\">\n              <label v-for=\"sec in settingsStore.settings.Zsections\" :key=\"sec.id\" class=\"flex items-center gap-1 cursor-pointer\">\n                <input\n                  v-model=\"selectedSections\"\n                  type=\"checkbox\"\n                  :value=\"sec.id\"\n                  class=\"accent-[var(--f-accent)]\"\n                >\n                <span>{{ sec.name }}</span>\n              </label>\n            </div>\n          </div>\n          <div>\n            <label class=\"text-[11px] text-[var(--f-text-secondary)] block mb-1\">讨论方向 / 话题关键词（可选，留空则由 AI 自由发挥）</label>\n            <textarea\n              v-model=\"genTopic\"\n              class=\"w-full text-xs px-2 py-1.5 rounded outline-none border focus:border-[var(--f-accent)] resize-none\"\n              :style=\"{ backgroundColor: 'var(--f-bg-input)', color: 'var(--f-text)', borderColor: 'var(--f-border-hover)' }\"\n              rows=\"3\"\n              placeholder=\"例如：最近更新的新副本、PK大赛、装备强化黑幕、生活玩家日常…&#10;多个话题可以用逗号或换行分隔\"\n            ></textarea>\n          </div>\n        </div>\n        <button\n          class=\"w-full text-xs text-white py-2 rounded disabled:opacity-50 mt-2 flex items-center justify-center gap-1 transition-colors\"\n          :class=\"forumStore.isGenerating ? 'bg-[var(--f-bg-input)] cursor-wait' : 'bg-[var(--f-accent-bg)] hover:bg-[var(--f-accent-bg-hover)]'\"\n          :disabled=\"forumStore.isGenerating || (genMode !== 'single' && selectedSections.length === 0)\"\n          @click=\"handleBatchGenerate\"\n        >\n          <i v-if=\"forumStore.isGenerating\" class=\"fa-solid fa-spinner fa-spin\"></i>\n          {{ forumStore.isGenerating ? '生成中，请稍候...' : '开始生成' }}\n        </button>\n      </template>\n\n      <!-- 日志面板 -->\n      <template v-else>\n        <div class=\"flex-1 overflow-y-auto space-y-2\">\n          <div v-if=\"settingsStore.generationLogs.length === 0\" class=\"text-center text-[var(--f-text-muted)] text-xs py-8\">\n            <i class=\"fa-solid fa-inbox mb-1 block text-lg\"></i>\n            暂无生成记录\n          </div>\n          <div\n            v-for=\"log in settingsStore.generationLogs\"\n            :key=\"log.id\"\n            class=\"rounded border p-2 text-[11px] cursor-pointer transition-colors\"\n            :style=\"{\n              backgroundColor: 'var(--f-bg-card)',\n              borderColor: expandedLogId === log.id ? 'var(--f-accent)' : 'var(--f-border)',\n            }\"\n            @click=\"toggleLogExpand(log.id)\"\n          >\n            <div class=\"flex items-center justify-between gap-2\">\n              <div class=\"flex items-center gap-1.5 min-w-0\">\n                <span\n                  class=\"inline-block w-1.5 h-1.5 rounded-full shrink-0\"\n                  :style=\"{ backgroundColor: log.error ? 'var(--f-danger)' : log.parsedCount === 0 ? '#f59e0b' : 'var(--f-author)' }\"\n                ></span>\n                <span class=\"font-medium truncate\">{{ logTypeLabel(log.type) }} · {{ log.sectionName }}</span>\n              </div>\n              <span class=\"text-[var(--f-text-muted)] shrink-0\">{{ formatLogTime(log.timestamp) }}</span>\n            </div>\n            <div class=\"flex items-center justify-between mt-1 text-[10px] text-[var(--f-text-secondary)]\">\n              <span>\n                <span v-if=\"log.error\" class=\"text-[var(--f-danger)]\"><i class=\"fa-solid fa-circle-xmark\"></i> {{ log.error }}</span>\n                <span v-else-if=\"log.parsedCount === 0\" class=\"text-amber-400\"><i class=\"fa-solid fa-triangle-exclamation\"></i> 解析出 0 条</span>\n                <span v-else class=\"text-[var(--f-author)]\"><i class=\"fa-solid fa-check\"></i> {{ log.parsedCount }} 条</span>\n                <span v-if=\"log.topic\" class=\"ml-1 opacity-70\">· {{ log.topic }}</span>\n              </span>\n              <span>{{ (log.durationMs / 1000).toFixed(1) }}s</span>\n            </div>\n            <!-- 展开详情 -->\n            <div v-if=\"expandedLogId === log.id\" class=\"mt-2 space-y-2 border-t pt-2\" :style=\"{ borderColor: 'var(--f-border)' }\">\n              <div>\n                <div class=\"flex items-center justify-between mb-0.5\">\n                  <span class=\"text-[10px] font-bold text-[var(--f-text-secondary)]\">System Prompt</span>\n                  <button class=\"text-[10px] text-[var(--f-accent)]\" @click.stop=\"copyText(log.systemPrompt)\">复制</button>\n                </div>\n                <pre class=\"max-h-32 overflow-y-auto rounded p-1.5 text-[10px] whitespace-pre-wrap break-all\" :style=\"{ backgroundColor: 'var(--f-bg-input)' }\">{{ log.systemPrompt }}</pre>\n              </div>\n              <div>\n                <div class=\"flex items-center justify-between mb-0.5\">\n                  <span class=\"text-[10px] font-bold text-[var(--f-text-secondary)]\">User Input</span>\n                  <button class=\"text-[10px] text-[var(--f-accent)]\" @click.stop=\"copyText(log.userInput)\">复制</button>\n                </div>\n                <pre class=\"max-h-32 overflow-y-auto rounded p-1.5 text-[10px] whitespace-pre-wrap break-all\" :style=\"{ backgroundColor: 'var(--f-bg-input)' }\">{{ log.userInput }}</pre>\n              </div>\n              <div>\n                <div class=\"flex items-center justify-between mb-0.5\">\n                  <span class=\"text-[10px] font-bold text-[var(--f-text-secondary)]\">Raw Response</span>\n                  <button class=\"text-[10px] text-[var(--f-accent)]\" @click.stop=\"copyText(log.rawResponse)\">复制</button>\n                </div>\n                <pre class=\"max-h-48 overflow-y-auto rounded p-1.5 text-[10px] whitespace-pre-wrap break-all\" :style=\"{ backgroundColor: 'var(--f-bg-input)' }\">{{ log.rawResponse || '（无返回内容）' }}</pre>\n              </div>\n            </div>\n          </div>\n        </div>\n        <button\n          v-if=\"settingsStore.generationLogs.length > 0\"\n          class=\"w-full text-xs py-2 rounded mt-2 flex items-center justify-center gap-1 transition-colors\"\n          :style=\"{ backgroundColor: 'var(--f-danger-bg)', color: 'var(--f-danger)', border: '1px solid var(--f-danger)' }\"\n          @click=\"settingsStore.clearGenerationLogs()\"\n        >\n          <i class=\"fa-solid fa-trash-can\"></i> 清空日志\n        </button>\n      </template>\n    </div>\n\n    <SettingsPanel v-if=\"showSettings\" @close=\"showSettings = false\" />\n    </div>\n  </div>\n</template>\n\n<script setup lang=\"ts\">\nimport { ref, inject, computed, watch } from 'vue';\nimport type { ForumPost, ForumComment } from './types';\nimport { useForumSettingsStore, useForumUiStore } from './settings';\nimport { generatePosts, generatePostsMerged, generatePostsSequential, generateComments, injectForumContext, cleanupOrphanPosts } from './aiGenerator';\nimport ForumTabs from './ForumTabs.vue';\nimport PostList from './PostList.vue';\nimport PostDetail from './PostDetail.vue';\nimport TournamentCard from './TournamentCard.vue';\nimport TournamentDetail from './TournamentDetail.vue';\nimport NewspaperCard from './NewspaperCard.vue';\nimport NewspaperDetail from './NewspaperDetail.vue';\nimport PostEditor from './PostEditor.vue';\nimport SettingsPanel from './SettingsPanel.vue';\n\nconst settingsStore = useForumSettingsStore();\nconst forumStore = useForumUiStore();\n\nconst showSettings = ref(false);\nconst genTopic = ref('');\nconst genMode = ref<'single' | 'merged' | 'sequential'>('single');\nconst selectedSections = ref<string[]>([forumStore.activeSection]);\n\nconst bgImageStyle = computed(() => ({\n  backgroundImage: `url(${settingsStore.settings.ZbgImage})`,\n}));\n\nconst bgBlurStyle = computed(() => ({\n  backdropFilter: `blur(${settingsStore.settings.ZbgBlur}px)`,\n  WebkitBackdropFilter: `blur(${settingsStore.settings.ZbgBlur}px)`,\n}));\n\nconst bgOverlayStyle = computed(() => ({\n  backgroundColor: 'var(--f-bg)',\n  opacity: settingsStore.settings.ZbgOpacity / 100,\n}));\n\nconst customThemeVars = computed(() => {\n  if (settingsStore.settings.Ztheme !== 'custom') return {};\n  const { ZcustomBg, ZcustomAccent, ZcustomText, ZcustomCardBg } = settingsStore.settings;\n  return {\n    '--f-bg': ZcustomBg,\n    '--f-text': ZcustomText,\n    '--f-accent': ZcustomAccent,\n    '--f-bg-card': ZcustomCardBg,\n    '--f-accent-bg': ZcustomAccent,\n    '--f-accent-bg-hover': ZcustomAccent,\n    '--f-accent-dim': ZcustomBg,\n    '--f-text-secondary': ZcustomText,\n    '--f-text-muted': ZcustomText,\n    '--f-author': ZcustomAccent,\n    '--f-border': ZcustomText,\n    '--f-border-hover': ZcustomAccent,\n    '--f-bg-input': ZcustomCardBg,\n    '--f-bg-hover': ZcustomCardBg,\n    '--f-danger': '#f87171',\n    '--f-danger-bg': '#7f1d1d',\n  } as Record<string, string>;\n});\n\nconst currentSectionType = computed(() => settingsStore.getSectionType(forumStore.activeSection));\n\nconst genButtonText = computed(() => {\n  if (currentSectionType.value === 'tournament') return 'AI生成比赛';\n  if (currentSectionType.value === 'newspaper') return 'AI生成报纸';\n  return 'AI生成帖子';\n});\n\nconst postButtonText = computed(() => {\n  if (currentSectionType.value === 'tournament') return '添加比赛';\n  if (currentSectionType.value === 'newspaper') return '发报纸';\n  return '发帖';\n});\n\nconst genDialogTitle = computed(() => {\n  if (currentSectionType.value === 'tournament') return 'AI 批量生成比赛';\n  if (currentSectionType.value === 'newspaper') return 'AI 批量生成报纸';\n  return 'AI 批量生成帖子';\n});\n\nconst windowControls = inject<{ requestClose: boolean }>('windowControls')!;\n\nfunction requestClose() {\n  if (windowControls) windowControls.requestClose = true;\n}\n\nfunction handleRefresh() {\n  try {\n    const store = useForumSettingsStore();\n    store.reloadFromVars();\n    cleanupOrphanPosts();\n    toastr.success('[论坛] 数据已刷新');\n  } catch (e: any) {\n    toastr.error(`[论坛] 刷新失败: ${e?.message}`);\n  }\n}\n\nfunction openGenDialog() {\n  genMode.value = 'single';\n  selectedSections.value = [forumStore.activeSection];\n  forumStore.openGenDialog();\n}\n\n// ── 生成日志辅助 ──\nconst expandedLogId = ref<string | null>(null);\n\nfunction toggleLogExpand(id: string) {\n  expandedLogId.value = expandedLogId.value === id ? null : id;\n}\n\nfunction logTypeLabel(type: string) {\n  if (type === 'posts') return '帖子';\n  if (type === 'comments') return '评论';\n  if (type === 'merged_posts') return '合并帖子';\n  return type;\n}\n\nfunction formatLogTime(ts: number) {\n  const d = new Date(ts);\n  const now = new Date();\n  const isToday = d.getFullYear() === now.getFullYear() && d.getMonth() === now.getMonth() && d.getDate() === now.getDate();\n  const pad = (n: number) => String(n).padStart(2, '0');\n  const timeStr = `${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}`;\n  if (isToday) return timeStr;\n  return `${pad(d.getMonth() + 1)}/${pad(d.getDate())} ${timeStr}`;\n}\n\nasync function copyText(text: string) {\n  try {\n    await navigator.clipboard.writeText(text);\n    toastr.success('已复制到剪贴板');\n  } catch {\n    toastr.error('复制失败');\n  }\n}\n\nasync function handleBatchGenerate() {\n  forumStore.isGenerating = true;\n  forumStore.startGenerationTimer();\n  try {\n    const topic = genTopic.value.trim() || undefined;\n    let resultMap: Record<string, ForumPost[]>;\n\n    if (genMode.value === 'single') {\n      const posts = await generatePosts(forumStore.activeSection, topic);\n      resultMap = { [forumStore.activeSection]: posts };\n    } else if (genMode.value === 'merged') {\n      const sections = selectedSections.value.length > 0 ? selectedSections.value : [forumStore.activeSection];\n      resultMap = await generatePostsMerged(sections, topic);\n    } else {\n      const sections = selectedSections.value.length > 0 ? selectedSections.value : [forumStore.activeSection];\n      resultMap = await generatePostsSequential(sections, topic);\n    }\n\n    let totalCount = 0;\n    for (const [sectionId, posts] of Object.entries(resultMap)) {\n      for (const post of posts) {\n        settingsStore.addPost(post);\n      }\n      totalCount += posts.length;\n    }\n    injectForumContext();\n    toastr.success(`AI生成了${totalCount}个帖子`);\n    forumStore.closeGenDialog();\n    genTopic.value = '';\n  } catch (e) {\n    toastr.error(`生成帖子失败: ${e instanceof Error ? e.message : String(e)}`);\n  } finally {\n    forumStore.isGenerating = false;\n    forumStore.stopGenerationTimer();\n  }\n}\n\nasync function handleGenerateComments() {\n  if (!forumStore.selectedPost) return;\n  forumStore.isGenerating = true;\n  forumStore.startGenerationTimer();\n  try {\n    const comments = await generateComments(forumStore.activeSection, forumStore.selectedPost);\n    for (const comment of comments) {\n      settingsStore.addComment(forumStore.activeSection, forumStore.selectedPost.id, comment);\n    }\n    injectForumContext();\n    toastr.success(`AI生成了${comments.length}条评论`);\n  } catch (e) {\n    toastr.error(`生成评论失败: ${e instanceof Error ? e.message : String(e)}`);\n  } finally {\n    forumStore.isGenerating = false;\n    forumStore.stopGenerationTimer();\n  }\n}\n\nfunction handleDeletePost() {\n  if (!forumStore.selectedPostId) return;\n  forumStore.deletePost(forumStore.selectedPostId);\n  injectForumContext();\n}\n\nfunction handleSubmitPost(post: ForumPost) {\n  settingsStore.addPost(post);\n  forumStore.closeEditor();\n  injectForumContext();\n  if (settingsStore.settings.ZautoAiReply) {\n    triggerAutoAiReply(post.id);\n  }\n}\n\nfunction handleSubmitComment(postId: string, comment: ForumComment) {\n  settingsStore.addComment(forumStore.activeSection, postId, comment);\n  forumStore.closeEditor();\n  injectForumContext();\n  if (settingsStore.settings.ZautoAiReply) {\n    triggerAutoAiReply(postId);\n  }\n}\n\nasync function triggerAutoAiReply(postId: string) {\n  const post = settingsStore.settings.Zposts[forumStore.activeSection].find(p => p.id === postId);\n  if (!post) return;\n  forumStore.isGenerating = true;\n  forumStore.startGenerationTimer();\n  try {\n    const comments = await generateComments(forumStore.activeSection, post);\n    for (const comment of comments) {\n      settingsStore.addComment(forumStore.activeSection, postId, comment);\n    }\n    injectForumContext();\n    toastr.success(`AI自动回复了${comments.length}条评论`);\n  } catch (e: any) {\n    console.warn('[网游论坛] 自动AI回复失败:', e);\n    toastr.error(`自动AI回复失败：${e?.message || e}`);\n  } finally {\n    forumStore.isGenerating = false;\n    forumStore.stopGenerationTimer();\n  }\n}\n</script>\n\n<style>\n.theme-classic-dark {\n  --f-bg: #111827;\n  --f-bg-card: #1f2937;\n  --f-bg-input: #374151;\n  --f-bg-hover: #4b5563;\n  --f-text: #e5e7eb;\n  --f-text-secondary: #9ca3af;\n  --f-text-muted: #6b7280;\n  --f-border: #374151;\n  --f-border-hover: #4b5563;\n  --f-accent: #60a5fa;\n  --f-accent-bg: #2563eb;\n  --f-accent-bg-hover: #3b82f6;\n  --f-accent-dim: #1e3a5f;\n  --f-author: #4ade80;\n  --f-danger: #f87171;\n  --f-danger-bg: #7f1d1d;\n}\n.theme-classic-dark .forum-window {\n  box-shadow: inset 0 1px 0 rgba(255,255,255,0.04);\n}\n.theme-cyberpunk {\n  --f-bg: #0a0a1a;\n  --f-bg-card: #12122e;\n  --f-bg-input: #1a1a42;\n  --f-bg-hover: #252560;\n  --f-text: #d0d0ff;\n  --f-text-secondary: #8888cc;\n  --f-text-muted: #555588;\n  --f-border: #2a2a5e;\n  --f-border-hover: #3a3a7e;\n  --f-accent: #00ffff;\n  --f-accent-bg: #0099bb;\n  --f-accent-bg-hover: #00bbdd;\n  --f-accent-dim: #003344;\n  --f-author: #ff00ff;\n  --f-danger: #ff3366;\n  --f-danger-bg: #4d0022;\n}\n.theme-cyberpunk .forum-window {\n  text-shadow: 0 0 10px rgba(0,255,255,0.06);\n}\n.theme-vaporwave {\n  --f-bg: #1a0a2e;\n  --f-bg-card: #2d1b4e;\n  --f-bg-input: #3d2d6e;\n  --f-bg-hover: #4d3d8e;\n  --f-text: #f0e0ff;\n  --f-text-secondary: #c8a0e0;\n  --f-text-muted: #8866aa;\n  --f-border: #4d3d7e;\n  --f-border-hover: #5d4d9e;\n  --f-accent: #ff71ce;\n  --f-accent-bg: #b967ff;\n  --f-accent-bg-hover: #cc77ff;\n  --f-accent-dim: #4a1942;\n  --f-author: #01cdfe;\n  --f-danger: #ff6b6b;\n  --f-danger-bg: #4a1919;\n}\n.theme-vaporwave .forum-window {\n  background: linear-gradient(\n    180deg,\n    rgba(255,113,206,0.05) 0%,\n    transparent 25%,\n    rgba(185,103,255,0.03) 50%,\n    transparent 75%,\n    rgba(255,113,206,0.04) 100%\n  );\n}\n.theme-terminal {\n  --f-bg: #0a0a0a;\n  --f-bg-card: #141414;\n  --f-bg-input: #1e1e1e;\n  --f-bg-hover: #282828;\n  --f-text: #33ff33;\n  --f-text-secondary: #22cc22;\n  --f-text-muted: #117711;\n  --f-border: #224422;\n  --f-border-hover: #336633;\n  --f-accent: #33ff33;\n  --f-accent-bg: #22aa22;\n  --f-accent-bg-hover: #33cc33;\n  --f-accent-dim: #113311;\n  --f-author: #88ff88;\n  --f-danger: #ff4444;\n  --f-danger-bg: #330000;\n}\n.theme-terminal .forum-window {\n  background-image: repeating-linear-gradient(\n    0deg,\n    transparent,\n    transparent 2px,\n    rgba(51,255,51,0.015) 2px,\n    rgba(51,255,51,0.015) 4px\n  );\n}\n.theme-terminal .fa-solid,\n.theme-terminal .fa-robot {\n  color: var(--f-accent);\n}\n.theme-light {\n  --f-bg: #f3f4f6;\n  --f-bg-card: #ffffff;\n  --f-bg-input: #e5e7eb;\n  --f-bg-hover: #d1d5db;\n  --f-text: #111827;\n  --f-text-secondary: #4b5563;\n  --f-text-muted: #9ca3af;\n  --f-border: #d1d5db;\n  --f-border-hover: #9ca3af;\n  --f-accent: #2563eb;\n  --f-accent-bg: #2563eb;\n  --f-accent-bg-hover: #1d4ed8;\n  --f-accent-dim: #dbeafe;\n  --f-author: #059669;\n  --f-danger: #dc2626;\n  --f-danger-bg: #fee2e2;\n}\n.theme-light .forum-window {\n  box-shadow: inset 0 1px 0 rgba(255,255,255,0.8);\n}\n.theme-dark-gold {\n  --f-bg: #0d0d0d;\n  --f-bg-card: #171714;\n  --f-bg-input: #252520;\n  --f-bg-hover: #33332c;\n  --f-text: #e8dcc8;\n  --f-text-secondary: #a09078;\n  --f-text-muted: #6b5e4e;\n  --f-border: #3a3020;\n  --f-border-hover: #5a4a30;\n  --f-accent: #c9a84c;\n  --f-accent-bg: #b08d38;\n  --f-accent-bg-hover: #c9a84c;\n  --f-accent-dim: #2a2410;\n  --f-author: #d4a574;\n  --f-danger: #b54a3a;\n  --f-danger-bg: #3d1a14;\n}\n.theme-dark-gold .forum-window {\n  box-shadow:\n    inset 0 1px 0 rgba(201,168,76,0.08),\n    inset 0 -1px 0 rgba(0,0,0,0.4);\n}\n.theme-dark-gold .fa-solid,\n.theme-dark-gold .fa-robot {\n  color: var(--f-accent);\n  text-shadow: 0 0 6px rgba(201,168,76,0.25);\n}\n.theme-parchment {\n  --f-bg: #ddd5c5;\n  --f-bg-card: #d0c8b8;\n  --f-bg-input: #c8c0b0;\n  --f-bg-hover: #c0b8a8;\n  --f-text: #362618;\n  --f-text-secondary: #5c4a32;\n  --f-text-muted: #887a64;\n  --f-border: #c0b8a0;\n  --f-border-hover: #b4ac90;\n  --f-accent: #7a5a10;\n  --f-accent-bg: #7a5a10;\n  --f-accent-bg-hover: #8f6e18;\n  --f-accent-dim: #e8e0d0;\n  --f-author: #4a6830;\n  --f-danger: #9c3a2a;\n  --f-danger-bg: #ead8d0;\n}\n.theme-parchment .forum-window {\n  background-image:\n    url(\"data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.85' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)' opacity='0.04'/%3E%3C/svg%3E\"),\n    radial-gradient(ellipse at center, transparent 50%, rgba(54,38,24,0.04) 100%);\n}\n.forum-window {\n  width: 100%;\n  height: 100%;\n}\n</style>\n"],"sourceRoot":""}]);
